using System;
using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// Setup
var smallAnalyzer = new TextAnalyzer("The quick brown fox jumps over the lazy dog");

var rng = new Random(42);
var words = new string[1000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(2, 12);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
var largeAnalyzer = new TextAnalyzer(string.Join(' ', words));

Console.WriteLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"OS: {RuntimeInformation.OSDescription}");
Console.WriteLine();

// Warmup + benchmark helper
static (double meanNs, double stddevNs) Bench(Action action, int warmup = 200, int iterations = 50)
{
    for (int i = 0; i < warmup; i++) action();

    var timings = new double[iterations];
    for (int run = 0; run < iterations; run++)
    {
        // Each "iteration" does 1000 inner calls to get measurable time
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < 1000; i++) action();
        sw.Stop();
        timings[run] = sw.Elapsed.TotalNanoseconds / 1000.0; // ns per call
    }

    double mean = 0;
    for (int i = 0; i < timings.Length; i++) mean += timings[i];
    mean /= timings.Length;

    double variance = 0;
    for (int i = 0; i < timings.Length; i++)
        variance += (timings[i] - mean) * (timings[i] - mean);
    double stddev = Math.Sqrt(variance / timings.Length);

    return (mean, stddev);
}

Console.WriteLine($"{"Method",-35} {"Mean (ns)",12} {"StdDev (ns)",12}");
Console.WriteLine(new string('-', 61));

var benchmarks = new (string Name, Action Act)[]
{
    ("AverageWordLength (small)",  () => smallAnalyzer.AverageWordLength()),
    ("AverageWordLength (large)",  () => largeAnalyzer.AverageWordLength()),
    ("WordLengthHistogram (small)", () => smallAnalyzer.WordLengthHistogram()),
    ("WordLengthHistogram (large)", () => largeAnalyzer.WordLengthHistogram()),
    ("UniqueWordCount (small)",    () => smallAnalyzer.UniqueWordCount()),
    ("UniqueWordCount (large)",    () => largeAnalyzer.UniqueWordCount()),
};

foreach (var (name, act) in benchmarks)
{
    var (mean, stddev) = Bench(act);
    Console.WriteLine($"{name,-35} {mean,12:F2} {stddev,12:F2}");
}

