static (double medianNs, double iqrNs) Bench(Action action, int warmup = 500, int iterations = 100)
{
    for (int i = 0; i < warmup; i++) action();

    var timings = new double[iterations];
    for (int run = 0; run < iterations; run++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < 5000; i++) action();
        sw.Stop();
        timings[run] = sw.Elapsed.TotalNanoseconds / 5000.0;
    }

    Array.Sort(timings);
    double median = timings[timings.Length / 2];
    double q1 = timings[timings.Length / 4];
    double q3 = timings[timings.Length * 3 / 4];

    return (median, q3 - q1);
}

arguments.old_str:
static (double meanNs, double stddevNs) Bench(Action action, int warmup = 500, int iterations = 100)
{
    for (int i = 0; i < warmup; i++) action();

    var timings = new double[iterations];
    for (int run = 0; run < iterations; run++)
    {
        // Each "iteration" does 1000 inner calls to get measurable time
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < 1000; i++) action();
        sw.Stop();
        timings[run] = sw.Elapsed.TotalNanoseconds / 1000.0; // ns per call
    }

    double mean = 0;
    for (int i = 0; i < timings.Length; i++) mean += timings[i];
    mean /= timings.Length;

    double variance = 0;
    for (int i = 0; i < timings.Length; i++)
        variance += (timings[i] - mean) * (timings[i] - mean);
    double stddev = Math.Sqrt(variance / timings.Length);

    return (mean, stddev);
}

